<div class="row g-4"><div class="col-xl-4"><div class="card shadow-sm"><div class="card-body"><h1 class="h4">Issue Equipment</h1><form method="post" action="/portal/equipment-custody" class="row g-3"><?=csrf_field()?><div class="col-12"><label class="form-label">Inventory Item</label><select name="inventory_item_id" class="form-select"><option value="">None</option><?php foreach($items as $i):?><option value="<?=$i['id']?>"><?=e($i['name'])?></option><?php endforeach?></select></div><div class="col-12"><label class="form-label">Vehicle</label><select name="vehicle_id" class="form-select"><option value="">None</option><?php foreach($vehicles as $v):?><option value="<?=$v['id']?>"><?=e($v['name'])?></option><?php endforeach?></select></div><div class="col-12"><label class="form-label">Assigned Employee</label><select name="assigned_user_id" class="form-select" required><?php foreach($users as $u):?><option value="<?=$u['id']?>"><?=e($u['name'])?></option><?php endforeach?></select></div><div class="col-6"><label class="form-label">Quantity</label><input type="number" step="0.01" name="quantity" value="1" class="form-control"></div><div class="col-6"><label class="form-label">Expected Return</label><input type="datetime-local" name="expected_return_at" class="form-control"></div><div class="col-12"><label class="form-label">Condition Out</label><input name="condition_out" class="form-control"></div><div class="col-12"><label class="form-label">Notes</label><textarea name="notes" class="form-control"></textarea></div><div class="col-12"><button class="btn btn-primary w-100">Issue Item</button></div></form></div></div></div><div class="col-xl-8"><div class="card shadow-sm"><div class="table-responsive"><table class="table align-middle mb-0"><thead><tr><th>Item</th><th>Assigned To</th><th>Issued</th><th>Expected</th><th>Status</th><th></th></tr></thead><tbody><?php foreach($rows as $r):?><tr><td><?=e($r['item_name']??$r['vehicle_name']??'Equipment assignment')?></td><td><?=e($r['assigned_name'])?></td><td><?=e($r['issued_at'])?></td><td><?=e($r['expected_return_at']??'')?></td><td><?=$r['returned_at']?'<span class="badge text-bg-secondary">Returned</span>':'<span class="badge text-bg-primary">Issued</span>'?></td><td><?php if(!$r['returned_at']):?><form method="post" action="/portal/equipment-custody/<?=$r['id']?>/return" class="d-flex gap-2"><?=csrf_field()?><input name="condition_in" class="form-control form-control-sm" placeholder="Condition in"><button class="btn btn-sm btn-outline-success">Return</button></form><?php endif?></td></tr><?php endforeach?></tbody></table></div></div></div></div>
